from pathlib import Path

async def execute(self, inputs):
    p = inputs.get('path') or self.get_parameter('path', '')
    exist_ok = inputs.get('exist_ok') if inputs.get('exist_ok') is not None else self.get_parameter('exist_ok', True)
    try:
        if not p:
            try: self.log_info('Create Folder: path is empty')
            except Exception: pass
            res = False
        else:
            path = Path(p)
            path.mkdir(parents=True, exist_ok=bool(exist_ok))
            res = True
    except Exception as e:
        try: self.log_info(f'Create Folder error: {e}')
        except Exception: pass
        res = False

    await self.set_output('result', res)
    await self.set_output('exec_out', True)
    return {'result': res}
